class CombinationIterator {
public:
    CombinationIterator(string characters, int combinationLength) {
        this->characters = characters;
        this->combinationLength = combinationLength;
        this->current = vector<char>(combinationLength);
        generateNextCombination();
    }

    string next() {
        string result = string(current.begin(), current.end());
        generateNextCombination();
        return result;
    }

    bool hasNext() {
        return !current.empty();
    }
private:
    string characters;
    int combinationLength;
    vector<char> current;

    void generateNextCombination() {
        for (int i = combinationLength - 1; i >= 0; i--) {
            if (i < combinationLength - 1 && current[i] < characters[i + 1]) {
                current[i]++;
                for (int j = i + 1; j < combinationLength; j++) {
                    current[j] = characters[j + (current[i] - characters[j])];
                }
                return;
            }
        }
        current.clear();
    }
};
